const allItems = $input.all();
const seen = new Set();
const jobs = [];

for (const item of allItems) {
  const results = item.json.results || [];
  for (const job of results) {
    const key = `${job.company?.display_name}-${job.title}`;
    if (!seen.has(key)) {
      seen.add(key);
      jobs.push({
        json: {
          title: job.title,
          company: job.company?.display_name || 'Unknown',
          location: job.location?.display_name || 'Unknown',
          description: (job.description || '').substring(0, 800),
          url: job.redirect_url || `https://www.adzuna.in/details/${job.id}`,
          salary_min: job.salary_min || null,
          salary_max: job.salary_max || null,
          created: job.created,
          id: job.id
        }
      });
    }
  }
}

return jobs;

const items = $input.all();
const results = [];

for (const item of items) {
  const job = item.json;

  try {
    const response = await fetch('http://host.docker.internal:11434/api/generate', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'llama3.2',
        stream: false,
        prompt: `You are a job fit analyzer. Score this job for a candidate with the following profile:\n\nSkills: Java, Spring Boot, Python, JavaScript, TypeScript, React.js, Angular, Node.js, Flask, FastAPI, REST APIs, CI/CD, Kubernetes, Docker\nExperience: 1 year full-stack at a software company\nTarget role: SDE-1 / Associate Software Engineer\nLocation: Open to anywhere in India + remote\n\nJob Title: ${job.title}\nCompany: ${job.company}\nDescription: ${job.description}\n\nReturn ONLY this exact JSON with no explanation, no markdown, no extra text:\n{"score": 7, "reason": "one line reason", "apply": true}`
      })
    });

    const data = await response.json();
    const aiText = (data.response || '').trim();

    let parsed;
    try {
      const match = aiText.match(/\{[^{}]+\}/);
      parsed = match ? JSON.parse(match[0]) : { score: 0, reason: 'parse error', apply: false };
    } catch {
      parsed = { score: 0, reason: 'parse error', apply: false };
    }

    results.push({
      json: {
        title: job.title,
        company: job.company,
        location: job.location,
        url: job.url,
        salary_min: job.salary_min,
        salary_max: job.salary_max,
        created: job.created,
        ai_score: parsed.score || 0,
        ai_reason: parsed.reason || 'Unknown',
        should_apply: (parsed.apply === true) && ((parsed.score || 0) >= 6)
      }
    });

  } catch (err) {
    results.push({
      json: {
        title: job.title,
        company: job.company,
        location: job.location,
        url: job.url,
        salary_min: job.salary_min,
        salary_max: job.salary_max,
        created: job.created,
        ai_score: 0,
        ai_reason: 'Ollama error: ' + err.message,
        should_apply: false
      }
    });
  }
}

return results;
